





UPDATE `spt`.`dp_measurement` SET `name`='Штука (шт)' WHERE `id`='5' and`activity_status_id`='2';
UPDATE `spt`.`dp_measurement` SET `name`='Грамм (гр)' WHERE `id`='4' and`activity_status_id`='2';
UPDATE `spt`.`dp_measurement` SET `name`='Килограмм (кг)' WHERE `id`='3' and`activity_status_id`='2';
UPDATE `spt`.`dp_measurement` SET `name`='Литр (лт)' WHERE `id`='2' and`activity_status_id`='2';
UPDATE `spt`.`dp_measurement` SET `name`='Метр (м)' WHERE `id`='1' and`activity_status_id`='2';


DROP  VIEW IF EXISTS `view_remains`;
CREATE 
    ALGORITHM = UNDEFINED 
    DEFINER = `root`@`localhost` 
    SQL SECURITY DEFINER
VIEW `view_remains` AS
    SELECT 
        `mv`.`acc_category_id` AS `acc_category_id`,
        `mv`.`dp_measurement_id` AS `dp_measurement_id`,
        `inv`.`to_stock_id` AS `stock_id`,
        SUM(`mv`.`remain`) AS `remain`
    FROM
        (`dp_stock_movements` `mv`
        LEFT JOIN `dp_invoice` `inv` ON ((`inv`.`id` = `mv`.`invoice_id`)))
    WHERE
        (`inv`.`service_type_id` = 1)
    GROUP BY `inv`.`to_stock_id` , `mv`.`acc_category_id` , `mv`.`dp_measurement_id`;


